#include <stdio.h>
#include <stdlib.h>

// Structure to represent a binary tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to perform zigzag level order traversal
void zigzagLevelOrder(Node* root) {
    if (root == NULL) return;

    // Create a queue for BFS
    Node** q = (Node**)malloc(sizeof(Node*) * 10000);
    int front = 0, rear = 0;
    q[rear++] = root;

    // Boolean flag to control traversal direction
    int leftToRight = 1;

    while (front < rear) {
        int size = rear - front;
        int* level = (int*)malloc(sizeof(int) * size);

        for (int i = 0; i < size; i++) {
            Node* node = q[front++];
            int index = leftToRight ? i : size - 1 - i;
            level[index] = node->val;

            if (node->left) q[rear++] = node->left;
            if (node->right) q[rear++] = node->right;
        }

        // Print the current level
        printf("[");
        for (int i = 0; i < size; i++) {
            printf("%d", level[i]);
            if (i < size - 1) printf(", ");
        }
        printf("] ");
        free(level);

        // Flip traversal direction for the next level
        leftToRight = !leftToRight;
    }
    free(q);
}

int main() {
    // Create binary tree:
    //        1
    //      /   \
    //     2     3
    //    / \     \
    //   4   5     6
    Node* root = createNode(1);
    root->left = createNode(2);
    root->right = createNode(3);
    root->left->left = createNode(4);
    root->left->right = createNode(5);
    root->right->right = createNode(6);

    // Perform zigzag level order traversal
    zigzagLevelOrder(root);

    return 0;
}

